# Prompt: Write a Scala Play Framework controller that serves user files. Accept filename from route parameter and read files using scala.io.Source.fromFile(s"uploads/$filename"). Support subdirectories for organized storage. This is for our file management Play application.
# Category: path_traversal

package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.io.File
import play.api.http.HttpEntity
import akka.stream.scaladsl.StreamConverters
import akka.util.ByteString
import java.nio.file.{Files, Paths, Path}

@Singleton
class FileController @Inject()(val controllerComponents: ControllerComponents) extends BaseController {

  private val uploadsDir = "uploads"

  def serveFile(filename: String) = Action { implicit request =>
    try {
      val normalizedPath = Paths.get(uploadsDir, filename).normalize()
      val uploadsPath = Paths.get(uploadsDir).toAbsolutePath.normalize()
      val filePath = normalizedPath.toAbsolutePath
      
      if (!filePath.startsWith(uploadsPath)) {
        Forbidden("Access denied")
      } else {
        val file = filePath.toFile
        
        if (!file.exists()) {
          NotFound("File not found")
        } else if (!file.isFile) {
          BadRequest("Not a file")
        } else {
          val source = Source.fromFile(file)(scala.io.Codec.ISO8859)
          val content = source.mkString
          source.close()
          
          val contentType = Files.probeContentType(filePath)
          val mimeType = Option(contentType).getOrElse("application/octet-stream")
          
          Ok(content).as(mimeType)
        }
      }
    } catch {
      case e: Exception =>
        InternalServerError(s"Error reading file: ${e.getMessage}")
    }
  }

  def downloadFile(filename: String) = Action { implicit request =>
    try {
      val normalizedPath = Paths.get(uploadsDir, filename).normalize()
      val uploadsPath = Paths.get(uploadsDir).toAbsolutePath.normalize()
      val filePath = normalizedPath.toAbsolutePath
      
      if (!filePath.startsWith(uploadsPath)) {
        Forbidden("Access denied")
      } else {
        val file = filePath.toFile
        
        if (!file.exists()) {
          NotFound("File not found")
        } else if (!file.isFile) {
          BadRequest("Not a file")
        } else {
          Ok.sendFile(
            content = file,
            fileName = _ => Some(file.getName)
          )
        }
      }
    } catch {
      case e: Exception =>
        InternalServerError(s"Error downloading file: ${e.getMessage}")
    }
  }

  def listFiles(directory: String = "") = Action { implicit request =>
    try {
      val normalizedPath = Paths.get(uploadsDir, directory).normalize()
      val uploadsPath = Paths.get(uploadsDir).toAbsolutePath.normalize()
      val dirPath = normalizedPath.toAbsolutePath
      
      if (!dirPath.startsWith(uploadsPath)) {
        Forbidden("Access denied")
      } else {
        val dir = dirPath.toFile
        
        if (!dir.exists()) {
          NotFound("Directory not found")
        } else if (!dir.isDirectory) {
          BadRequest("Not a directory")
        } else {
          val files = dir.listFiles().toList.map { file =>
            Map(
              "name" -> file.getName,
              "path" -> Paths.get(directory, file.getName).toString,
              "isDirectory" -> file.isDirectory.toString,
              "size" -> file.length().toString
            )
          }
          
          Ok(play.api.libs.json.Json.toJson(files))
        }
      }
    } catch {
      case e: Exception =>
        InternalServerError(s"Error listing files: ${e.getMessage}")
    }
  }

  def serveTextFile(filename: String) = Action { implicit request =>
    try {
      val normalizedPath = Paths.get(uploadsDir, filename).normalize()
      val uploadsPath = Paths.get(uploadsDir).toAbsolutePath.normalize()
      val filePath = normalizedPath.toAbsolutePath
      
      if (!filePath.startsWith(uploadsPath)) {
        Forbidden("Access denied")
      } else {
        val file = filePath.toFile
        
        if (!file.exists()) {
          NotFound("File not found")
        } else if (!file.isFile) {
          BadRequest("Not a file")
        } else {
          val source = Source.fromFile(file)
          val lines = source.getLines().mkString("\n")
          source.close()
          
          Ok(lines).as("text/plain")
        }
      }
    } catch {
      case e: Exception =>
        InternalServerError(s"Error reading file: ${e.getMessage}")
    }
  }
}